data.131-结构体#13.1 结构体:
void main() { /* 张老太养了两只猫猫:一只名字叫小白,今年 3 岁,白色。 还有一只叫小花,今年 100 岁,花色。 请编写一个程序， 当用户输入小猫的名字时， 就显示该猫的名字， 年龄， 颜色。 如果用户输入的小猫名错误， 则显示 张老太没有这只猫猫。 分析： 1. 猫猫有 三个成员(变量)组成 2. 使用结构体解决 */ // 创建 结构体 Cat 【是数据类型】 struct Cat { // 结构体名 Cat, Cat 就是我们自己构造的一个数据类型 char * name; //名字， 使用指针， 指向一个字符串 int age; //年龄 char *color; //颜色 }; // 使用 Cat 结构体， 创建变量 struct Cat cat1; // cat1 就是 struct Cat 的一个变量 struct Cat cat2; // cat2 就是 struct Cat 的一个变量 // 给 cat1 的各个成员赋值 cat1.name = "小白"; cat1.age = 3; cat1.color = "白色"; //给 cat2 的各个成员赋值 cat2.name = "小花"; cat2.age = 100; cat2.color = "花色"; //输出两只猫的信息 printf("\n 第 1 只猫 name=%s age=%d color=%s", cat1.name, cat1.age, cat1.color); printf("\n 第 2 只猫 name=%s age=%d color=%s", cat2.name, cat2.age, cat2.color); } 结构体和结构体变量的区别和联系 结构体是自定义的数据类型， 表示的是一种数据类型. 结构体变量代表一个具体变量 其实就是面向对象里面说的，类 和 对象之间的关系。
声明结构体
struct 结构体名称 { // 结构体名首字母大写， 比如 Cat, Person 成员列表; }; struct Student{ char *name; //姓名 int num; //学号 int age; //年龄 char group; //所在学习小组 float score; //成绩 //成员也可以是结构体 }; 成员
成员是结构体的一个组成部分，一般是基本数据类型、也可以是数组、指针、结构体等。 成员声明语法同变量，示例：数据类型 成员名; 字段的类型可以为：基本类型、数组或指针、结构体等。 在创建一个结构体变量后，需要给成员赋值，如果没有赋值就使用可能导致程序异常终止。 不同结构体变量的成员是独立，互不影响，一个结构体变量的成员更改，不影响另外一个。 创建方式1
struct Stu{ char *name; //姓名 int num; //学号 int age; //年龄 char group; //所在学习小组 float score; //成绩 }; struct Stu stu1, stu2; // 定义了两个变量 stu1 和 stu2， 它们都是 Stu 类型， 都由 5 个成员组成 // 注意关键字 struct 不能少 创建方式2
struct Stu{ char *name; //姓名 int num; //学号 int age; //年龄 char group; //所在学习小组 float score; //成绩 } stu1, stu2; // 在定义结构体 Stu 的同时， 创建了两个结构体变量 stu1 和 stu2 创建方式3
// 如果只需要 stu1、 stu2 两个变量， 后面不需要再使用结构体数据类型， struct { // 没有写 Stu char *name; //姓名 int num; //学号 int age; //年龄 char group; //所在学习小组 float score; //成绩 } stu1, stu2; stu1.name = "tom"; stu1.num = 100;.... // 1. 该结构体数据类型， 没有名, 匿名结构体 // 2. stu1 和 stu2 就是 该结构体的两个变量 成员获取和赋值
获取：结构体变量名.成员名;
赋值：
struct Student stu3 = {“林黛玉 2”, 12, 16, ‘A’, 100 };
struct Student{ char *name; //姓名 int num; //学号 int age; //年龄 char group; //所在小组 float score; //成绩 } stu1 = {"贾宝玉", 11, 18, 'B', 90.50}, stu2 = { "林黛玉", 12, 16, 'A', 100 }; struct Student stu4; //stu4 = {"林黛玉 2", 12, 16, 'A', 100 }; // 这样赋值不可以 常用操作
typedef struct stu { rt_base_t pin; rt_base_t mode; }stu_t; // 定义一个名字叫stu的结构体类型，然后又把这个类型重定义了个叫stu_t的类型。 // 后续创建结构体的时候，就只需要 // stu_t studentA; 就可以了 typedef Stu_t *stu_ptr; // 重定义了个指针类型 // stu_ptr studentA_t; // 效果等同于 // stu_t * studentA_t;

data.144-文件操作#14.4 文件操作:
打开文件
使用 fopen( ) 函数来创建一个新的文件或者打开一个已有的文件， 这个调用会初始化类型 FILE 的一个对象，类型 FILE 包含了所有用来控制流的必要的信息。
FILE *fopen( const char * filename, const char * mode );
filename 是字符串， 用来命名文件， 访问模式 mode 的值可以是下列值中的一个 如果处理的是二进制文件(图片， 视频..)， 则需使用下面的访问模式: “rb”, “wb”, “ab”, “rb+”, “r+b”, “wb+”, “w+b”, “ab+”, “a+b” //b :binary 二进制 关闭文件
关闭文件， 使用 fclose( ) 函数。int fclose( FILE *fp );
如果成功关闭文件， fclose( ) 函数返回零， 如果关闭文件时发生错误， 函数返回 EOF。 这个函数实际上， 会清空缓冲区中的数据， 关闭文件， 并释放用于该文件的所有内存。 EOF 是一个定义在头文件 stdio.h 中的常量。 C 标准库提供了各种函数来按字符或者以固定长度字符串的形式读写文件。 使用完文件后(读， 写)， 一定要将该文件关闭。 写入文件
下面是把字符写入到流中的函数
int fputc( int c, FILE *fp );
说明：函数 fputc() 把参数 c 的字符值写入到 fp 所指向的输出流中。 如果写入成功， 它会返回写入的字符，如果发生错误， 则会返回 EOF。 您可以使用下面的函数来把一个以 null 结尾的字符串写入到流中：
int fputs( const char *s, FILE *fp );
说明： 函数 fputs() 把字符串 s 写入到 fp 所指向的输出流中。 如果写入成功， 它会返回一个非负值， 如果发生错误， 则会返回 EOF。 您也可以使用 int fprintf(FILE *fp,const char *format, …) 函数来写把一个字符串写入到文件中
void main() { // 创建一个文件指针 FILE *fp = NULL; // 打开该文件 fp = fopen("d:/test100.txt", "w+"); // w+ 模式是 文件会被截断为零长度 // fp = fopen("d:/test100.txt", "a+"); //w+ 模式是 文件会被截断为零长度 // 将内容写入到文件中 /* fprintf(fp, "你好 北京~~ \n"); fputs("你好，上海~~ \n", fp); */ //关闭文件!!! fclose(fp); printf("创建， 写入信息完成"); } 读取文件
下面是从文件读取单个字符的函数
int fgetc( FILE * fp );
说明： fgetc() 函数从 fp 所指向的输入文件中读取一个字符。 返回值是读取的字符， 如果发生错误则返回 EOF。
下面的函数从流中读取一个字符串：
char *fgets( char *buf, int n, FILE *fp );
说明： 函数 fgets() 从 fp 所指向的输入流中读取 n - 1 个字符。 它会把读取的字符串复制到缓冲区 buf， 并在最后追加一个 null 字符来终止字符串。 如果这个函数在读取最后一个字符之前就遇到一个换行符 ‘\n’ 或文件的末尾 EOF， 则只会返回读取到的字符，包括换行符。 void main() { // 创建一个文件指针 FILE *fp = NULL; // 定义一个缓冲区 char buff[1024]; // 打开文件 fp = fopen("d:/test200.txt", "r"); // 方法 1 // fscanf(fp, "%s", buff); // 输出 // printf("%s\n", buff); // 方法 2 读取整个文件 // 说明， 循环读取 fp 指向的文件内容， 如果读到 NULL,就结束 while(fgets(buff, 1024,fp)!=NULL) { printf("%s", buff); } // 关闭文件 fclose(fp); getchar(); }

data.26-布尔类型#2.6 布尔类型:
C 语言标准(C89)没有定义布尔类型，所以 C 语言判断真假时以 0 为假，非 0 为真。 但这种做法不直观，所以我们可以借助 C 语言的宏定义。 C 语言标准(C99)提供了 _Bool 型， _Bool 仍是整数类型， 但与一般整型不同的是， _Bool 变量只能赋值为 0 或 1，非 0 的值都会被存储为 1。
_ C99 还提供了一个头文件 定义了 bool 代表_Bool，true 代表 1，false 代表 0。只要导入 stdbool.h，就能方便的操作布尔类型了 , 比如 bool flag = false;
//宏定义 #define BOOL int #define TURE 1 #define FALSE 0 int main(){ int isPass = -1; //定义一个布尔变量 BOOL isOk = TURE; // 等价 int isOK = 0 if(isPass) { // 0 表示假， 非 0 表示真 printf("通过考试"); } if(isOk) { printf("ok"); } return(0); }

data.72-枚举的遍历#7.2 枚举的遍历:
C 语言中，枚举类型是被当做 int 或者 unsigned int 类型来处理的，枚举类型必须连续是可以实现有条件的遍历。
以下实例使用 for 来遍历枚举的元素
// 遍历枚举元素 // day++ 会给出警告， 但是可以运行 for (day = MON; day <= SUN; day++) { // 要求枚举元素是连续赋值 printf("枚举元素： %d \n", day); }

data.810-基本数据类型和字符串类型的转换#8.10 基本数据类型和字符串类型的转换:
我们经常需要将基本数据类型转成字符串类型(即 char 数组 )。 或者将字符串类型转成基本数据类型。
sprintf 函数的用法 sprintf 和平时我们常用的 printf 函数的功能很相似。sprintf 函数打印到字符串中，而 printf 函数打印输出到屏幕上。sprintf 函数在我们完成其他数据类型转换成字符串类型的操作中应用广泛。 该函数包含在 stdio.h 的头文件中。 基本类型转字符串类型
#include int main(void) { char str1[20]; // 字符数组， 即字符串 char str2[20]; char str3[20]; int a = 20984, b = 48090; double d = 14.309948; // 说明 // 1. sprintf 是一个系统函数， 可以将结果存放到字符串中 // 2. 格式化的结果， 会存放到 str1 中 sprintf(str1, "%d %d", a, b); sprintf(str2, "%.2f", d); sprintf(str3, "%8.2f", d); // %8.2f 含义是格式化后， 一共有 8 位， 小数点后占用 2 位， 不够用空格占位 printf("str1=%s str2=%s str3=%s", str1, str2, str3); return 0; } 标准输出：str1=20984 48090 str2=14.31 str3= 14.31 字符串类型转基本数据类型
#include int main(void) { // 字符数组 char str[10] = "123456"; char str2[10] = "12.67423"; char str3[3] = "ab"; char str4[4] = "111"; // 说明 // 1. atoi(str) 将 str 转成整数 int num1 = atoi(str); short s1 = atoi(str4); // 说明 // 1. atof(str2); 将 str2 转成小数 double d = atof(str2); // 说明 // 1. str3[0] 表示获取到 str3 这个字符串(数组)的第一个元素 'a' char c = str3[0]; printf("num1=%d d=%f c=%c s1=%d", num1, d, c, s1);// return 0; } 标准输出：num1=123456 d=12.674230 c=a s1=111 注意事项 在将 char 数组 类型转成 基本数据类型时，要确保能够转成有效的数据，比如 我们可以把 “123” , 转成一个整数，但是不能把 “hello” 转成一个整数。 如果格式不正确，会默认转成 0 或者 0.0。

data.82-头文件#8.2 头文件:
在实际的开发中，我们往往需要在不同的文件中，去调用其它文件的定义的函数， 比如 hello.c 中，去使用myfuns.c 文件中的函数。
头文件 头文件是扩展名为 .h的文件， 包含了C 函数声明和宏定义， 被多个源文件中引用共享。 有两种类型的头文件：程序员编写的头文件和 C 标准库自带的头文件。 在程序中要使用头文件，需要使用C 预处理指令 #include来引用它。 前面我们已经看过 stdio.h 头文件，它是C 标准库自带的头文件。 #include 叫做文件包含命令， 用来引入对应的头文件（.h 文件）。#include 也是 C 语言预处理命令的一种。#include 的处理过程很简单， 就是将头文件的内容插入到该命令所在的位置， 从而把头文件和当前源文件连接成一个源文件， 这与复制粘贴的效果相同。 建议把所有的常量、宏、系统全局变量和函数原型写在头文件中，在需要的时候随时引用这些头文件。 如
myfun.c
#include int myCal(int n1, int n2, char oper) { //定义一个变量 res ,保存运算的结果 double res = 0.0; switch(oper) { case '+' : res = n1 + n2; break; case '-': res = n1 - n2; break; case '*': res = n1 * n2; break; case '/': res = n1 / n2; break; default : printf("你的运算符有误~"); } printf("\n%d %c %d = %.2f\n", n1, oper, n2, res); return res; } void sayHello() { //定义函数 printf("say Hello"); } myfun.h
#include // 声明函数 int myCal(int n1, int n2, char oper); void sayHello(); hello.c
#include //引入我们需要的头文件(用户头文件) #include "myfun.h" void main() { //使用 myCal 完成计算任务 int n1 = 10; int n2 = 50; char oper = '-'; double res = 0.0; //调用 myfun.c 中定义的函数 myCal res = myCal(n1, n2, oper); printf("\nres=%.2f", res); sayHello(); getchar(); } 使用细节 引用头文件相当于复制头文件的内容。 源文件的名字 可以不和头文件一样，但是为了好管理，一般头文件名和源文件名一样。 C 语言中 include <> 与 include "” 的区别 include <>：引用的是编译器的类库路径里面的头文件，用于引用系统头文件。 include “"：引用的是你程序目录的相对路径中的头文件，如果在程序目录没有找到引用的头文件则到编译器的类库路径的目录下找该头文件，用于引用用户头文件。 引用系统头文件，两种形式都会可以，include <> 效率高。引用用户头文件，只能使用 include “"。 一个 #include 命令只能包含一个头文件，多个头文件需要多个 #include 命令。 同一个头文件如果被多次引入，多次引入的效果和一次引入的效果相同，因为头文件在代码层面有防止重复引入的机制。 在一个被包含的文件(.c)中又可以包含另一个文件头文件(.h) 不管是标准头文件，还是自定义头文件，都只能包含变量和函数的声明，不能包含定义，否则在多次引入时会引起重复定义错误。

data.83-函数细节#8.3 函数细节:
函数的形参列表可以是多个。
C 语言传递参数可以是值传递（pass by value） ， 也可以传递指针（a pointer passed by value） 也叫引用传递。
函数的命名遵循标识符命名规范，首字母不能是数字，可以采用 驼峰法 或者 下划线法。
函数中的变量是局部的，函数外不生效。
基本数据类型默认是值传递的， 即进行值拷贝。在函数内修改，不会影响到原来的值。
// 基本数据类型默认是值传递的， 即进行值拷贝。 在函数内修改， 不会影响到原来的值 void f2(int n) { n++; printf("\n f2中的n=%d", n); // n=10 } void main() { //函数中的变量是局部的， 函数外不生效 //printf("num=%d", num); int n = 9; f2(n); printf("\n main 函数中 n=%d", n); // 9 getchar(); } 如果希望函数内的变量能修改函数外的变量，可以传入变量的地址&，函数内以指针的方式操作变量。从效果上看类似引用(即传递指针)
// 如果希望函数内的变量能修改函数外的变量，可以传入变量的地址&， // 函数内以指针的方式操作变量。 从效果上看类似引用(即传递指针) void f3(int *p) { (*p)++; // 修改会对函数外的变量有影响 } void main() { // 函数中的变量是局部的， 函数外不生效 // printf("num=%d", num); int n = 9; f3(&n); printf("\nmain 函数中 n=%d", n); //10 getchar(); } C 语言 不支持函数重载。
C 语言支持可变参数函数。
#include #include // 说明 // num 表示传递的参数格式 // ... 表示可以传递多个参数和 num 一致即可 int fun(int num, ...) // 可变函数， 即参数的个数可以不确定, 使用... 表示 { int i, totalSum=0; // totalSum 一定要初始化 int val = 0; va_list v1; // v1 实际是一个字符指针，从头文件里可以找到 va_start(v1, num); // 使 v1 指向可变列表中第一个值， 即 num 后的第一个参数 printf("*v = %d \n", *v1); for(i = 0; i < num; i++) //num 减一是为了防止下标超限 { val = va_arg(v1, int); // 该函数返回 v1 指向的值， 并使 v1 向下移动一个 int 的距离， 使其指向下一个 int printf("val = %d\n", val); // val = 10 val=30 val=60 totalSum += val; } va_end(v1); //关闭 v1 指针， 使其指向 null return totalSum; } void main() { int res = fun(8, 10,30,60, -100,1,5,7,98); printf("和是=%d", res); getchar(); }

data.132-系统时钟配置#1.3.2 系统时钟配置:
在 board.c 中实现 系统时钟配置（为 MCU、外设提供工作时钟）与 os tick 的配置 （为操作系统提供心跳 / 节拍）。
在board.c文件中修改如下函数，以完成系统初始化和 OS Tick 的配置。
#include "main.h" extern void SystemClock_Config(void); // 此函数默认是在main.c中，此处声明一下 /* cortex-m 架构使用 SysTick_Handler() */ void SysTick_Handler() { rt_interrupt_enter(); /* 进入中断时必须调用 */ rt_tick_increase(); /* RT-Thread 系统时钟计数 */ rt_interrupt_leave(); /* 退出中断时必须调用 */ } /** * This function will initial your board. */ void rt_hw_board_init(void) { /* * TODO 1: OS Tick Configuration * Enable the hardware timer and call the rt_os_tick_callback function * periodically with the frequency RT_TICK_PER_SECOND. */ /* 1、系统、时钟初始化 */ HAL_Init(); // 初始化 HAL 库 SystemClock_Config(); // 配置系统时钟 SystemCoreClockUpdate(); // 对系统时钟进行更新 /* 2、OS Tick 频率配置，RT_TICK_PER_SECOND = 1000 表示 1ms 触发一次中断 */ SysTick_Config(SystemCoreClock / RT_TICK_PER_SECOND); /* Call components board initial (use INIT_BOARD_EXPORT()) */ #ifdef RT_USING_COMPONENTS_INIT rt_components_board_init(); #endif #if defined(RT_USING_USER_MAIN) && defined(RT_USING_HEAP) rt_system_heap_init(rt_heap_begin_get(), rt_heap_end_get()); #endif } 另外，SysTick_Handler()函数在裸机工程中应该也有，也需要去stm32l4xx_it.c文件中注释掉。

data.14-led闪烁#1.4 LED闪烁:
在main.c中添加如下代码（注意：LED引脚初始化的代码在源代码中已经配置过了）
#include // 线程相关 int main(void) { MX_GPIO_Init(); while (1) { HAL_GPIO_WritePin(GPIOE, GPIO_PIN_7, GPIO_PIN_RESET); HAL_GPIO_WritePin(GPIOE, GPIO_PIN_8, GPIO_PIN_RESET); HAL_GPIO_WritePin(GPIOE, GPIO_PIN_9, GPIO_PIN_RESET); rt_thread_mdelay(500); HAL_GPIO_WritePin(GPIOE, GPIO_PIN_7, GPIO_PIN_SET); HAL_GPIO_WritePin(GPIOE, GPIO_PIN_8, GPIO_PIN_SET); HAL_GPIO_WritePin(GPIOE, GPIO_PIN_9, GPIO_PIN_SET); rt_thread_mdelay(500); } } 注意
这里使用的延时函数是由RTT提供的，此函数引起系统调度，切换到其他线程运行。 这里的main函数中不再执行初始化动作，RTT系统启动时已经做好了。 至此，将工程编译并下载，即可看到LED闪烁了。

data.5-内核配置及裁剪#5. 内核配置及裁剪:
rtconfig.c文件内容如下
/* RT-Thread config file */ #ifndef __RTTHREAD_CFG_H__ #define __RTTHREAD_CFG_H__ /* ********************** 基础部分 *************************/ /* 设置系统最大优先级，可设置范围 8 到 256，默认值 32 */ #define RT_THREAD_PRIORITY_MAX 32 /* 设置 RT-Thread 操作系统节拍，表示多少 tick 每秒 */ /* 时钟节拍率越快，系统的额外开销就越大。常用值为 100 或 1000。 */ #define RT_TICK_PER_SECOND 1000 /* 字节对齐时设定对齐的字节个数，默认 4，常使用 ALIGN(RT_ALIGN_SIZE) 进行字节对齐 */ #define RT_ALIGN_SIZE 4 /* 设置对象名称的最大长度，默认 8 个字符，一般无需修改 */ #define RT_NAME_MAX 8 /* 设置使用组件自动初始化功能，默认需要使用，开启该宏则可以使用自动初始化功能 */ #define RT_USING_COMPONENTS_INIT /* 开启 RT_USING_USER_MAIN 宏，则打开 user_main 功能，默认需要开启，这样才能调用 RT-Thread 的启动代码 */ /* main 线程的栈大小可修改 */ #define RT_USING_USER_MAIN #define RT_MAIN_THREAD_STACK_SIZE 1024 /* ********************** 内核调试部分 *************************/ /* 定义 RT_DEBUG 宏则开启 debug 模式。若开启系统调试，则在实现打印之后可以打印系统 LOG 日志。请在代码开发与调试过程中打开该项，帮助调试定位问题，在代码发布时关闭该项 */ //#define RT_DEBUG	// 关闭 debug #define RT_DEBUG_INIT 0	// 启用组件初始化调试配置，设置为 1 则会打印自动初始化的函数名称 //#define RT_USING_OVERFLOW_CHECK	// 关闭栈溢出检查 /* ********************** 钩子函数部分 *************************/ /* 设置是否使用钩子函数，默认关闭 */ //#define RT_USING_HOOK	// 是否 开启系统钩子功能 //#define RT_USING_IDLE_HOOK	// 是否 开启空闲线程钩子功能 /* ********************** 软件定时器部分 *************************/ /* 设置是否启用软件定时器，以及相关参数的配置，默认关闭 */ //#define RT_USING_TIMER_SOFT	// 是否 开启软件定时器功能 #define RT_TIMER_THREAD_PRIO 4	// 设置软件定时器线程的优先级，默认为 4 #define RT_TIMER_THREAD_STACK_SIZE 512	// 设置软件定时器线程的栈大小，默认为 512 字节 /* ********************** IPC 部分 *************************/ /* 系统支持的 IPC 有：信号量、互斥量、事件集、邮箱、消息队列。通过定义相应的宏打开或关闭该 IPC 的使用 */ #define RT_USING_SEMAPHORE	// 设置是否使用 信号量，默认打开 //#define RT_USING_MUTEX	// 设置是否使用 互斥量 //#define RT_USING_EVENT	// 设置是否使用 事件集 //#define RT_USING_MAILBOX	// 设置是否使用 邮箱 //#define RT_USING_MESSAGEQUEUE	// 设置是否使用 消息队列 /* ********************** 内存部分 *************************/ /* RT-Thread 内存管理包含：内存池、内存堆、小内存算法。通过开启相应的宏定义使用相应的功能 */ #define RT_USING_HEAP	// 是否使用 内存堆 #define RT_USING_SMALL_MEM	// 是否使用 小内存管理 //#define RT_USING_TINY_SIZE	// 是否使用 小体积的算法，牵扯到 rt_memset、rt_memcpy 所产生的体积 /* ********************** FinSH 部分 *************************/ #define RT_USING_CONSOLE	// 开启控制台功能，失能该宏则关闭控制台，不能实现打印 #define RT_CONSOLEBUF_SIZE 128	// 控制台缓冲大小（1-1024） /* 当系统加入 FinSH 组件源码后，需要在 rtconfig.h 中开启以下项。参考 finsh_config.h 中内容。若未加入 FinSH 组件源码，请勿开启此项。 */ #include "finsh_config.h" /* ********************** device 部分 *************************/ /* 当系统中加入 device 框架源码时，则需要在 rtconfig.h 中开启以下项。若未加入 device 源码，请勿开启此项 */ //#define RT_USING_DEVICE #endif finsh_config.h内容如下
/* FinSH config file */ #ifndef __MSH_CFG_H__ #define __MSH_CFG_H__ /* 打开 FinSH 组件 */ #define RT_USING_FINSH /* 使用 MSH 模式 */ #define FINSH_USING_MSH #define FINSH_USING_MSH_ONLY /* tshell 线程的优先级与线程栈大小 */ #define FINSH_THREAD_PRIORITY 21	// 请检查系统最大优先级的值，该值必须在系统支持的优先级范围之内 #define FINSH_THREAD_STACK_SIZE 1024 /* 使用符号表，使用命令描述 */ #define FINSH_USING_SYMTAB #define FINSH_USING_DESCRIPTION #endif

data.212-按键中断#2.1.2 按键中断:
在工程中新建一个文件夹，在文件夹中新建一个.c文件，添加以下内容。
编译下载后，在Shell窗口输入key_irq_test命令，然后按下按键，对应LED亮起。
/* * 程序清单：这是一个 PIN 设备绑定中断使用例程 * 例程导出了 key_irq_test 命令到控制终端 * 命令调用格式：key_irq_test * 程序功能：通过按键控制led亮灭 */ #include #include #include "drv_common.h" // KEY引脚定义 #define KEY0_PIN GET_PIN(E, 4) // RIGHT #define KEY2_PIN GET_PIN(E, 2) // LEFT // LED引脚定义 #define LED0_PIN GET_PIN(B, 5) #define LED1_PIN GET_PIN(E, 5) void led0_on(void *args) { rt_kprintf("led0 on, led1 off!\n"); rt_pin_write(LED0_PIN, PIN_LOW); rt_pin_write(LED1_PIN, PIN_HIGH); } void led1_on(void *args) { rt_kprintf("led0 off, led1 on!\n"); rt_pin_write(LED0_PIN, PIN_HIGH); rt_pin_write(LED1_PIN, PIN_LOW); } static void key_irq_test(void) { /* LED引脚为输出模式 */ rt_pin_mode(LED0_PIN, PIN_MODE_OUTPUT); rt_pin_mode(LED1_PIN, PIN_MODE_OUTPUT); /* 默认高电平 */ rt_pin_write(LED0_PIN, PIN_HIGH); rt_pin_write(LED1_PIN, PIN_HIGH); /* 按键0引脚为输入模式 */ rt_pin_mode(KEY0_PIN, PIN_MODE_INPUT_PULLUP); /* 绑定中断，下降沿模式，回调函数名为led0_on */ rt_pin_attach_irq(KEY0_PIN, PIN_IRQ_MODE_FALLING, led0_on, RT_NULL); /* 使能中断 */ rt_pin_irq_enable(KEY0_PIN, PIN_IRQ_ENABLE); /* 按键2引脚为输入模式 */ rt_pin_mode(KEY2_PIN, PIN_MODE_INPUT_PULLUP); /* 绑定中断，下降沿模式，回调函数名为led1_on */ rt_pin_attach_irq(KEY2_PIN, PIN_IRQ_MODE_FALLING, led1_on, RT_NULL); /* 使能中断 */ rt_pin_irq_enable(KEY2_PIN, PIN_IRQ_ENABLE); } /* 导出到 msh 命令列表中 */ MSH_CMD_EXPORT(key_irq_test, key irq test);

data.151-添加时基#1.5.1 添加时基:
在中断函数的文件中可以看到定时器的中断处理函数，在这里添加中断回调函数，处理 lvgl 的时基即可。
记得要在main中开启定时器中断，HAL_TIM_Base_Start_IT(&htim7);
#include "lvgl.h"	//添加在最上方 void HAL_TIM_PeriodElapsedCallback(TIM_HandleTypeDef *htim) { if(htim->Instance == TIM7) { lv_tick_inc(1); } }

data.152-显示部分#1.5.2 显示部分:
打开显示适配文件的宏定义，把 0 改为 1。 添加 lcd 显示驱动的头文件，因为下面需要调用里面的函数。 添加屏幕尺寸大小的宏定义。 下图中展示了上面三个步骤。
#include "lcd_lvgl.h" //	下面用到的	在 lcd.h中有 #define MY_DISP_HOR_RES	LCD_Width	//水平分辨率 #define MY_DISP_VER_RES	LCD_Height //纵向分辨率 lv_port_disp_init函数修改，选择一种缓冲区方式，注释掉另外两种；修改自己的屏幕尺寸。这里使用这种，省内存。 如果想使用第二种，记得把下面缓冲区的名字换一下。
第三种同理，但是多了下面还要打开一个full_flash的定义，并添加一个LV_VER_RES_MAX的宏定义，就是数当然也是越大越好，能直接为LV_DISP_HOR_RES应该是最好了。
显示初始化函数：添加 LCD 初始化函数。显示刷新函数：添加自己的显示接口。 刷新函数中注释掉的部分：LCD_Draw_ColorPoint函数，内容如下。但是我的驱动文件里没有添加。因为速度特别特别慢。
如果想用的话，把下面两个函数放到lcd_lvgl.c中，并在头文件中声明下面的画点函数即可。
static void LCD_Write_HalfWord(const uint16_t da) { uint8_t data[2] = {0}; data[0] = da >> 8; data[1] = da; LCD_WR(1); LCD_SPI_Send(data, 2); } void LCD_Draw_ColorPoint(uint16_t x, uint16_t y, uint16_t color) { LCD_Address_Set(x, y, x, y); LCD_Write_HalfWord(color); }

